## 3. The C/C++ stub (`pcapng_stubs.c`)

> **Important** – this file must be compiled with a C++ compiler
> (`g++`/`clang++`) because it includes the C++ header(s) of *libpcapng*.
> The OCaml runtime is still accessed through the C API (`caml/*`).

```c
/* ----------------------------------------------------------------------
 * pcapng_stubs.c – C/C++ glue for the libpcapng iterator
 *
 * Build command (example):
 *
 *   ocamlc -c -I +ocaml pcapng.mli
 *   ocamlc -c -I +ocaml pcapng.ml
 *   g++ -I $(OCAML_INCLUDE) -fPIC -c pcapng_stubs.c -o pcapng_stubs.o
 *   ocamlc -a -o libpcapng.cma pcapng.cmo pcapng_stubs.o -cclib -lpcapng
 *
 * Replace $(OCAML_INCLUDE) with the path returned by `ocamlc -where`.
 * ---------------------------------------------------------------------- */

#define CAML_NAME_SPACE
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/callback.h>
#include <caml/bigarray.h>
#include <caml/threads.h>

#include <string>
#include <exception>
#include <stdexcept>

/* ----------------------------------------------------------------------
 * The real C++ library we bind to.
 * (The actual header name may differ; adjust accordingly.)
 * ---------------------------------------------------------------------- */
#include "pcapng.hpp"          /* <- libpcapng's public C++ header */

/* ----------------------------------------------------------------------
 * Custom block that stores a pointer to the libpcapng Reader.
 * ---------------------------------------------------------------------- */
typedef struct {
  pcapng::Reader *reader;   /* owned by this block */
} pcapng_handle;

/* Forward declaration for the finaliser */
static void pcapng_finalize(value v);

/* Custom operations for the abstract handle */
static struct custom_operations pcapng_ops = {
  "pcapng_handle",
  pcapng_finalize,
  custom_compare_default,
  custom_hash_default,
  custom_serialize_default,
  custom_deserialize_default,
  custom_compare_ext_default,
  custom_fixed_length_default
};

/* ----------------------------------------------------------------------
 * Finaliser – called when the OCaml value is GC‑collected.
 * ---------------------------------------------------------------------- */
static void pcapng_finalize(value v)
{
  pcapng_handle *h = (pcapng_handle *)Data_custom_val(v);
  if (h->reader) {
    delete h->reader;
    h->reader = NULL;
  }
}

/* ----------------------------------------------------------------------
 * Helper: allocate a fresh custom block and store a newly created Reader.
 * ---------------------------------------------------------------------- */
static value alloc_handle(pcapng::Reader *r)
{
  value v = caml_alloc_custom(&pcapng_ops,
                              sizeof(pcapng_handle),
                              0,   /* no extra memory for the GC */
                              1);  /* finaliser is needed */
  pcapng_handle *h = (pcapng_handle *)Data_custom_val(v);
  h->reader = r;
  return v;
}

/* ----------------------------------------------------------------------
 * OCaml wrapper: open_file : string -> t
 * ---------------------------------------------------------------------- */
CAMLprim value pcapng_open(value filename_v)
{
  CAMLparam1(filename_v);
  const char *c_fname = String_val(filename_v);
  try {
    pcapng::Reader *r = new pcapng::Reader(std::string(c_fname));
    CAMLreturn(alloc_handle(r));
  } catch (const std::exception &e) {
    caml_failwith(e.what());
  }
}

/* ----------------------------------------------------------------------
 * OCaml wrapper: close : t -> unit
 * ---------------------------------------------------------------------- */
CAMLprim value pcapng_close(value handle_v)
{
  CAMLparam1(handle_v);
  pcapng_handle *h = (pcapng_handle *)Data_custom_val(handle_v);
  if (h->reader) {
    delete h->reader;
    h->reader = NULL;
  }
  CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
 * Helper: build an OCaml frame record from a libpcapng frame.
 *
 *   type frame = { ts : float; data : bytes }
 *
 *   The record tag is 0 and it has exactly two fields.
 * ---------------------------------------------------------------------- */
static value make_ocaml_frame(const pcapng::Frame &f)
{
  CAMLparam0();
  CAMLlocal1(ocaml_rec);

  /* Allocate the record (2 fields, tag 0) */
  ocaml_rec = caml_alloc(2, 0);

  /* ts : float */
  Store_field(ocaml_rec, 0, caml_copy_double(f.timestamp));

  /* data : bytes – we copy the raw payload into an OCaml string/bytes */
  size_t len = f.data.size();
  value data_v = caml_alloc_string(len);
  memcpy(String_val(data_v), f.data.data(), len);
  Store_field(ocaml_rec, 1, data_v);

  CAMLreturn(ocaml_rec);
}

/* ----------------------------------------------------------------------
 * OCaml wrapper: iter : (frame -> unit) -> t -> unit
 *
 *  The stub loops in C++, releasing the OCaml runtime while it reads
 *  from the file, and calls back into OCaml for each frame.
 * ---------------------------------------------------------------------- */
CAMLprim value pcapng_iter(value callback_v, value handle_v)
{
  CAMLparam2(callback_v, handle_v);
  CAMLlocal1(frame_v);

  pcapng_handle *h = (pcapng_handle *)Data_custom_val(handle_v);
  if (!h->reader)
    caml_failwith("pcapng_iter: handle already closed");

  /* --------------------------------------------------------------
   * The iterator may block on I/O, therefore we release the runtime.
   * -------------------------------------------------------------- */
  caml_release_runtime_system();

  try {
    pcapng::Frame f;
    while (h->reader->next(f)) {
      /* Re‑acquire the runtime before we invoke the OCaml callback.
       * This also re‑establishes the GC stack. */
      caml_acquire_runtime_system();

      frame_v = make_ocaml_frame(f);
      /* The callback receives a single argument (the frame). */
      caml_callback(callback_v, frame_v);

      /* After the callback we can safely release the runtime again
       * before the next iteration. */
      caml_release_runtime_system();
    }
  } catch (const std::exception &e) {
    caml_acquire_runtime_system();   /* make sure we own the runtime */
    caml_failwith(e.what());
  }

  caml_acquire_runtime_system();   /* final reacquire before returning */
  CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
 * OCaml wrapper: next : t -> frame option
 *
 *  Returns [Some frame] if a frame is available, otherwise [None].
 * ---------------------------------------------------------------------- */
CAMLprim value pcapng_next(value handle_v)
{
  CAMLparam1(handle_v);
  CAMLlocal1(res_v);

  pcapng_handle *h = (pcapng_handle *)Data_custom_val(handle_v);
  if (!h->reader)
    caml_failwith("pcapng_next: handle already closed");

  pcapng::Frame f;
  if (h->reader->next(f)) {
    /* Some f */
    value frame_v = make_ocaml_frame(f);
    res_v = caml_alloc(1, 0);          /* Some constructor */
    Store_field(res_v, 0, frame_v);
  } else {
    /* None */
    res_v = Val_int(0);
  }

  CAMLreturn(res_v);
}

/* ----------------------------------------------------------------------
 * OCaml wrapper: reset : t -> unit
 * ---------------------------------------------------------------------- */
CAMLprim value pcapng_reset(value handle_v)
{
  CAMLparam1(handle_v);
  pcapng_handle *h = (pcapng_handle *)Data_custom_val(handle_v);
  if (!h->reader)
    caml_failwith("pcapng_reset: handle already closed");

  /* libpcapng typically provides a reset/rewind method.  If it does not,
   * you could close & reopen the file, but most libraries expose it. */
  h->reader->reset();

  CAMLreturn(Val_unit);
}
```

