## 4. How to compile & link

Assuming the three files are placed in the same directory:

```sh
# 1. Compile the OCaml interface & implementation
ocamlc -c -I +ocaml pcapng.mli
ocamlc -c -I +ocaml pcapng.ml

# 2. Compile the stub with a C++ compiler (must see the libpcapng header)
OCAML_INC=$(ocamlc -where)
g++ -std=c++17 -I $OCAML_INC -I /usr/include/pcapng \
    -fPIC -c pcapng_stubs.c -o pcapng_stubs.o

# 3. Archive the native code into a library (static or shared is fine)
ocamlc -a -o libpcapng.cma pcapng.cmo pcapng_stubs.o -cclib -lpcapng

# 4. Use it from an OCaml program
cat > test.ml <<'EOF'
let () =
  let h = Pcapng.open_file "sample.pcapng" in
  (* Example 1: push‑style iteration *)
  Pcapng.iter (fun f ->
      Printf.printf "frame @ %.3f – %d bytes\n%!"
        f.Pcapng.ts (Bytes.length f.Pcapng.data)
    ) h;

  (* Example 2: pull‑style iteration *)
  let rec loop () =
    match Pcapng.next h with
    | None -> ()
    | Some f ->
        Printf.printf "pull frame @ %.3f – %d bytes\n%!"
          f.Pcapng.ts (Bytes.length f.Pcapng.data);
        loop ()
  in
  loop ();

  Pcapng.close h
EOF

ocamlc -I . -o test.native libpcapng.cma test.ml
./test.native
```

Replace `/usr/include/pcapng` and `-lpcapng` with the actual include and library paths of your `libpcapng` installation.

